import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const [workers, setWorkers] =
    useState([]);

  const [requests, setRequests] =
    useState([]);

  const [search, setSearch] =
    useState("");

  const [searched, setSearched] =
    useState(false);

  const [date, setDate] =
    useState("");

  const [time1, setTime1] =
    useState("");

  const [time2, setTime2] =
    useState("");

  const [time3, setTime3] =
    useState("");


  // LOAD REQUESTS

  useEffect(() => {

    fetchRequests();

  }, []);


  const fetchRequests = async () => {

    const user =
      JSON.parse(localStorage.getItem("user"));

    try {

      const res = await axios.get(
        `http://localhost:5000/api/request/customer/${user.name}`
      );

      setRequests(res.data);

    } catch (err) {

      console.log(err);
    }
  };


  // SEARCH WORKERS

  const searchWorkers = async () => {

    try {

      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter(worker =>

        worker.skills?.some(skill =>

          skill.toLowerCase().includes(
            search.toLowerCase()
          )
        )
      );

      setWorkers(filtered);

      setSearched(true);

    } catch (err) {

      alert("Failed");
    }
  };


  // SEND REQUEST

  const sendRequest = async (worker) => {

    const user =
      JSON.parse(localStorage.getItem("user"));

    try {

      await axios.post(
        "http://localhost:5000/api/request/send",
        {

          customerName: user.name,

          labourId: worker._id,

          labourName: worker.name,

          workType: search,

          date: date,

          timings: [
            time1,
            time2,
            time3
          ],

          status: "Pending",

          customerDecision:
            "Waiting"
        }
      );

      alert("Request Sent");

      fetchRequests();

    } catch (err) {

      alert("Failed");
    }
  };


  // CUSTOMER ACCEPT

  const customerAccept =
    async (id) => {

    try {

      await axios.put(
        `http://localhost:5000/api/request/customer-accept/${id}`
      );

      fetchRequests();

    } catch (err) {

      alert("Failed");
    }
  };


  // CUSTOMER REJECT

  const customerReject =
    async (id) => {

    try {

      await axios.put(
        `http://localhost:5000/api/request/customer-reject/${id}`
      );

      fetchRequests();

    } catch (err) {

      alert("Failed");
    }
  };


  // FIND REQUEST

  const getRequest = (workerId) => {

    return requests.find(
      req => req.labourId === workerId
    );
  };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        {/* TITLE */}

        <div style={styles.top}>

          <h1 style={styles.heading}>
            Find Workers
          </h1>

          <p style={styles.subtext}>
            Search and hire workers
          </p>

        </div>

        {/* SEARCH BOX */}

        <div style={styles.searchCard}>

          <input
            style={styles.input}
            placeholder="Search work type..."
            value={search}
            onChange={(e) =>
              setSearch(e.target.value)
            }
          />

          <input
            type="date"
            style={styles.input}
            value={date}
            onChange={(e) =>
              setDate(e.target.value)
            }
          />

          <select
            style={styles.input}
            onChange={(e) =>
              setTime1(e.target.value)
            }
          >
            <option>Time Slot 1</option>
            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
          </select>

          <select
            style={styles.input}
            onChange={(e) =>
              setTime2(e.target.value)
            }
          >
            <option>Time Slot 2</option>
            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
          </select>

          <select
            style={styles.input}
            onChange={(e) =>
              setTime3(e.target.value)
            }
          >
            <option>Time Slot 3</option>
            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
          </select>

          <button
            style={styles.searchBtn}
            onClick={searchWorkers}
          >
            Search
          </button>

        </div>

        {/* WORKERS */}

        <div style={styles.grid}>

          {workers.map(worker => {

            const req =
              getRequest(worker._id);

            return (

              <div
                key={worker._id}
                style={styles.card}
              >

                <div style={styles.profile}>

                  <div style={styles.avatar}>
                    {worker.name?.charAt(0)}
                  </div>

                  <div>

                    <h2 style={styles.name}>
                      {worker.name}
                    </h2>

                    <p style={styles.skills}>
                      {worker.skills?.join(", ")}
                    </p>

                  </div>

                </div>

                {/* INFO */}

                <p style={styles.info}>
                  📍 {worker.city},
                  {" "}
                  {worker.area}
                </p>

                <p style={styles.info}>
                  📞 {worker.phone}
                </p>

                {/* STATUS */}

                {req && (

                  <div style={styles.statusSection}>

                    {/* LABOUR STATUS */}

                    {req.status ===
                    "Pending" && (

                      <p style={styles.pending}>
                        Labour Response Pending
                      </p>

                    )}

                    {req.status ===
                    "Accepted" && (

                      <p style={styles.accepted}>
                        Labour Accepted • ₹
                        {" "}
                        {req.labourPrice}
                      </p>

                    )}

                    {req.status ===
                    "Rejected" && (

                      <p style={styles.rejected}>
                        Labour Rejected
                      </p>

                    )}

                    {/* CUSTOMER ACTION */}

                    {req.status ===
                    "Accepted" &&
                    req.customerDecision ===
                    "Waiting" && (

                      <div
                        style={
                          styles.buttonRow
                        }
                      >

                        <button
                          style={
                            styles.acceptBtn
                          }
                          onClick={() =>
                            customerAccept(
                              req._id
                            )
                          }
                        >
                          Accept
                        </button>

                        <button
                          style={
                            styles.rejectBtn
                          }
                          onClick={() =>
                            customerReject(
                              req._id
                            )
                          }
                        >
                          Reject
                        </button>

                      </div>

                    )}

                    {/* FINAL STATUS */}

                    {req.customerDecision ===
                    "Accepted" && (

                      <p
                        style={
                          styles.finalAccepted
                        }
                      >
                        Work Confirmed
                      </p>

                    )}

                    {req.customerDecision ===
                    "Rejected" && (

                      <p
                        style={
                          styles.finalRejected
                        }
                      >
                        Work Rejected
                      </p>

                    )}

                  </div>

                )}

                {/* SEND BUTTON */}

                {!req && (

                  <button
                    style={
                      styles.requestBtn
                    }
                    onClick={() =>
                      sendRequest(worker)
                    }
                  >
                    Send Request
                  </button>

                )}

              </div>
            );
          })}

        </div>

      </div>

    </div>
  );
}

